query:
SELECT id, title, status, totalChunks, errorMessage, createdAt FROM materials ORDER BY createdAt DESC LIMIT 5;
SELECT COUNT(*) as chunk_count, materialId FROM material_chunks GROUP BY materialId;
SELECT COUNT(*) as chunks_with_vectors FROM material_chunks WHERE vectorId IS NOT NULL;

